	('dispositifs_prevention', '[{"titre": "Eau à disposition", "description": "Points d''eau potable gratuits et en libre-service accessibles à tous pendant toute la durée de l''événement."}, {"titre": "Poste de secours", "description": "Espace dédié et clairement identifié, avec le matériel nécessaire pour assurer les premiers soins."}, {"titre": "Espace de repos", "description": "Zone calme, isolée du bruit et surveillée, permettant aux participants de se reposer en toute sécurité."}, {"titre": "Stand de prévention", "description": "Espace d''information et de distribution de matériel de réduction des risques (éthylotests, préservatifs, bouchons d''oreilles)."}, {"titre": "SAM", "description": "Dispositif ''Capitaine de soirée'' récompensant les conducteurs sobres."}, {"titre": "Affichage des horaires de transport en commun", "description": "Affichage visible des horaires des derniers bus, tramways ou métros à proximité des sorties."}, {"titre": "Navettes", "description": "Capacité des membre du club à pouvoir conduire les participant chez eux si besoin."}, {"titre": "Taxis", "description": "Capacité à contacter rapidement un taxi ou VTC pour ramener quelqu''un chez lui si besoin."}]', 'Liste des disposition à prendre en cas de débit de boisson', '2026-04-05 22:04:26.17+00', 'a7f51451-594b-4499-bc98-c864cae7e12d');
